  .ora-page-emoji-btn:hover { background: var(--color-notion-sidebar-hover); }

  .ora-emoji-picker-popover { position: absolute; top: 44px; left: 0; z-index: 50; background: var(--color-notion-bg); border: 1px solid var(--color-notion-divider); border-radius: 8px; box-shadow: 0 4px 16px rgba(0,0,0,0.1); width: 320px; padding: 10px; }
