  .ora-emoji-picker-btn:hover, .ora-emoji-picker-btn.selected { background: var(--color-notion-sidebar-hover); }

  .ora-page-title { font-size: 36px; font-weight: 700; line-height: 1.2; color: var(--color-notion-text); outline: none; margin: 0; padding: 4px 0; min-height: 1.2em; cursor: text; }
  .ora-page-title:empty::before { content: attr(data-placeholder); color: var(--color-notion-text-light); pointer-events: none; }
  .ora-page-title:focus { background: rgba(0,0,0,0.02); }

  .ora-block-row { position: relative; display: flex; align-items: flex-start; gap: 4px; }
  .ora-block-row > ora-block-handle { flex: 0 0 auto; margin-top: 6px; opacity: 0; transition: opacity 0.15s ease; }
  .ora-block-row:hover > ora-block-handle { opacity: 1; }
  .ora-block-row > .ora-block-host { flex: 1 1 auto; min-width: 0; }

  .ora-cover-picker-popover { position: absolute; top: 208px; left: 50%; transform: translateX(-50%); z-index: 50; display: flex; gap: 8px; background: var(--color-notion-bg); border: 1px solid var(--color-notion-divider); border-radius: 8px; box-shadow: 0 4px 16px rgba(0,0,0,0.1); padding: 12px; }
  .ora-cover-swatch { width: 32px; height: 32px; border-radius: 4px; border: 1px solid rgba(0,0,0,0.08); cursor: pointer; transition: transform 0.1s; }
  .ora-cover-swatch:hover { transform: scale(1.12); }
  .ora-cover-swatch-default { background: #fff; position: relative; }
  .ora-cover-swatch-default::after { content: '✕'; position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%); color: #aaa; font-size: 14px; }

  [data-locked-by] { border-left: 2px solid var(--lock-color, var(--color-notion-blue)); padding-left: 8px; }
}

