    this.handleEvent("focus_block_caret", ({ block_id, position }) => {
      if (block_id === this.el.getAttribute("block-id")) {
        if (position === "start") {
          this.el.focusStart?.();
        } else if (position === "end") {
          this.el.focusEnd?.();
        }
      }
    });

