/**
 * @vitest-environment jsdom
 */
import { describe, it, expect, beforeEach } from "vitest";
import { createEditor, $getRoot, ParagraphNode, TextNode } from "lexical";
import {
  moveCaretToStart,
  moveCaretToEnd,
  toggleFormat,
  applyLink,
} from "../../lexical/commands.js";
import { oraTheme } from "../../lexical/theme.js";

const EDITOR_NODES = [ParagraphNode, TextNode];

function createTestEditor() {
  const root = document.createElement("div");
  root.setAttribute("contenteditable", "true");
  document.body.appendChild(root);

  const editor = createEditor({
    namespace: "test",
    nodes: EDITOR_NODES,
    theme: oraTheme,
    onError: (e) => console.error("Lexical:", e),
  });

  editor.setRootElement(root);
  return { editor, root };
}

function insertTwoParagraphs(editor) {
  editor.update(() => {
    const root = $getRoot();
    const p1 = new ParagraphNode();
    p1.append(new TextNode("First paragraph"));
    const p2 = new ParagraphNode();
    p2.append(new TextNode("Second paragraph"));
    root.append(p1, p2);
  });
}

describe("moveCaretToStart", () => {
  let editor;

  beforeEach(() => {
    const setup = createTestEditor();
    editor = setup.editor;
  });

  it("does not throw on non-empty root", () => {
    insertTwoParagraphs(editor);
    expect(() => moveCaretToStart(editor)).not.toThrow();
  });

  it("does not throw on empty root", () => {
    expect(() => moveCaretToStart(editor)).not.toThrow();
  });

  it("preserves content after call", () => {
    insertTwoParagraphs(editor);
    moveCaretToStart(editor);

    let text = "";
    editor.getEditorState().read(() => {
      text = $getRoot().getTextContent();
    });
    expect(text).toBe("First paragraphSecond paragraph");
  });

  it("empty root still readable after call", () => {
    moveCaretToStart(editor);
    let text = "";
    editor.getEditorState().read(() => {
      text = $getRoot().getTextContent();
    });
    expect(text).toBe("");
  });

  it("root.select() fallback on empty executes without crashing", () => {
    // Ensures the empty-branch (r.select()) of the ternary works
    moveCaretToStart(editor);
    // Simply verifies the editor is still functional
    let childCount = 0;
    editor.getEditorState().read(() => {
      childCount = $getRoot().getChildren().length;
    });
    expect(childCount).toBe(0);
  });
});

describe("moveCaretToEnd", () => {
  let editor;

  beforeEach(() => {
    const setup = createTestEditor();
    editor = setup.editor;
  });

  it("does not throw on non-empty root", () => {
    insertTwoParagraphs(editor);
    expect(() => moveCaretToEnd(editor)).not.toThrow();
  });

  it("does not throw on empty root", () => {
    expect(() => moveCaretToEnd(editor)).not.toThrow();
  });

  it("preserves content after call", () => {
    insertTwoParagraphs(editor);
    moveCaretToEnd(editor);

    let text = "";
    editor.getEditorState().read(() => {
      text = $getRoot().getTextContent();
    });
    expect(text).toBe("First paragraphSecond paragraph");
  });

  it("empty root still readable after call", () => {
    moveCaretToEnd(editor);
    let text = "";
    editor.getEditorState().read(() => {
      text = $getRoot().getTextContent();
    });
    expect(text).toBe("");
  });

  it("root.select() fallback on empty executes without crashing", () => {
    moveCaretToEnd(editor);
    let childCount = 0;
    editor.getEditorState().read(() => {
      childCount = $getRoot().getChildren().length;
    });
    expect(childCount).toBe(0);
  });
});

describe("helpers are exported", () => {
  it("exports toggleFormat and applyLink (unchanged)", () => {
    expect(typeof toggleFormat).toBe("function");
    expect(typeof applyLink).toBe("function");
  });

  it("exports moveCaretToStart and moveCaretToEnd", () => {
    expect(typeof moveCaretToStart).toBe("function");
    expect(typeof moveCaretToEnd).toBe("function");
  });
});

